@namespace 'AccordionContainer';
@st-import AccordionHeader from '/b75181d7dd29e3febf9e0f1888338194fb05936f.st.css';

:import {
  -st-from: '../../../stylable/params.js';
  -st-named: getVar;
}

:vars {
  animation-time: getVar(--animation-time);
  content-height: getVar(--content-height);
  direction: getVar(--direction, inherit);
  align: getVar(--align, inherit);
}

.container {
  min-height: auto !important;
}

.root {
  display: flex;
  flex-direction: column;
  gap: var(--itemSpacing, '0px');
  position: relative;
  z-index: 0;
}

.accordion {
  -st-states: isOpened;
}

.accordionHeader {
  -st-extends: AccordionHeader;
  display: flex;
  flex-wrap: nowrap;
  flex-direction: var(--flexDirection);
  align-items: center;
  width: 100%;
  cursor: pointer;
  direction: value(direction);
  padding: calc(var(--vPadding) * 1px) calc(var(--hPadding) * 1px);
  column-gap: calc(var(--hPadding) * 1px);
  position: relative;
  z-index: 1;
  text-align: value(align);
}

.accordionHeader::accordionLabel {
  flex-grow: 1;
  text-align: value(align);
}

.accordionHeader::accordionIcon {
  display: flex;
  flex-shrink: 0;
}

.animationBox {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows calc(value(animation-time) * 1s) ease-out;
}

.accordion:isOpened > .animationBox {
  grid-template-rows: 1fr;
}

.accordionContent {
  -st-states: isContentHidden;
  overflow: clip;
  min-height: 0;
}

.accordionContent:isContentHidden {
  display: none;
}

/* root of Accordion item should have "display: none"
   for the editor to handle it properly */
.accordionContent:isContentHidden > div {
  display: none;
}

