@namespace "Breadcrumbs";

@property st-global(--horizontalMargin);
@property st-global(--verticalMargin);
@property st-global(--alignment);
@property st-global(--direction);

:import {
  -st-from: "/6e53c85062d31ba972a71bdd5b7cfc2c8142f09e.st.css";
  -st-named: mobile-only;
}

.root {
  -archetype: paintBox;
  overflow: visible;
  direction: var(--direction);
}

.list {
  display: flex !important;
  align-items: center;
  justify-content: var(--alignment);
  flex-direction: row;
  flex-wrap: wrap;
  row-gap: var(--verticalMargin);
  column-gap: var(--horizontalMargin);
}

.breadcrumb-icon {
  height: 100%;
}

.breadcrumb:last-child .separator {
  display: none !important;
}

.list .breadcrumb:not(.breadcrumb-icon) {
  min-width: calc(3em + var(--horizontalMargin) * 2);
}

@st-scope .mobile-only {
  .list.only-previous .breadcrumb {
    flex-direction: row-reverse;
  }

  .list.only-previous .breadcrumb:last-child .separator {
    display: initial !important;
    margin-inline-end: var(--horizontalMargin);
  }
}

.breadcrumb {
  letter-spacing: 0;
  padding: inherit;
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: row;
  cursor: default;
  position: relative;
}

.breadcrumb-content {
  -st-states: isCurrent;
  -archetype: textBox;
  box-sizing: content-box;
  font-size: 14px;
  color: inherit;
  overflow: hidden;
  display: flex !important;
  height: 1em;
  cursor: pointer;
  margin-inline-end: var(--horizontalMargin);
}

.breadcrumb:last-child .breadcrumb-content {
  margin-inline-end: 0;
}

.breadcrumb-content:isCurrent {
  -archetype: noPaddingTextBox;
  padding: inherit;
}

.breadcrumb-content:hover {
  -archetype: noPaddingTextBox;
}

.breadcrumb-content::after {
    opacity: 0;
    content: "";
}

.breadcrumb-content:focus::after,
.breadcrumb-content:hover::after {
    opacity: 0;
    content: "";
}

.breadcrumb-content[data-breadcrumb-ellipsis="true"]:focus::after,
.breadcrumb-content[data-breadcrumb-ellipsis="true"]:hover::after {
    opacity: 1;
    content: attr(aria-label);
    position: absolute;
    top: 100%;
    background-color: rgb(95, 95, 95);
    font-size: 11px;
    font-weight: 900;
    color: white;
    padding: 0 5px;
    white-space: nowrap;
    border-style: solid;
    border-width: 2px;
    border-color: rgb(110,110,110);
    z-index: 1;
}

.label {
  color: inherit;
  align-self: center;
  text-overflow: ellipsis;
  overflow: hidden;
  white-space: nowrap;
  direction: var(--direction);
}

.separator {
  -archetype: text;
  font-size: 14px;
  color: black;
  align-self: center;
  letter-spacing: 0;
  cursor: default;
}

.icon {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100%;
}

.icon > svg {
  width: 1em;
  height: auto;
}

