:import {
  -st-from: '../../../../stylable/params.js';
  -st-named: getVar;
}

.root {
  display: flex;
  flex-direction: column-reverse;
  align-items: flex-start;
}

.text-wrapper {
  width: 100%;
}

.text {
  -archetype: text;
  -st-states:
    collapse,
    textFormat(enum(rtf, plain)),
    wrappingStyle(enum(single-line, multi-line)),
    withSafariListsFix;
  font-size: 16px;
  letter-spacing: 0em;
  width: 100%;
  word-break: break-word;
}

.text:textFormat(plain) {
  white-space: pre-wrap;
}

.text ul {
  padding-inline-start: 1.3em;
  margin-inline-start: 0.5em;
  list-style: disc;
}

.text ol {
  padding-inline-start: 1.3em;
  margin-inline-start: 0.5em;
  list-style: decimal;
}

.text:wrappingStyle(multi-line):collapse {
  display: -webkit-box;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: getVar('--max-lines', 1);
  overflow-x: visible;
  overflow-y: clip;
}

/*
  We need to show all inner elements as "display: inline" due to bug in Safari.
  We also need to add new line break via this weird "\A".
  @see https://stackoverflow.com/questions/70897195/line-clamp-webkit-not-working-in-safari
 */
 .text:wrappingStyle(multi-line) > *:not(ul, ol),
 .text:withSafariListsFix > ul,
 .text:withSafariListsFix > ol {
  display: inline;
 }

 .text:wrappingStyle(multi-line) > *:not(ul, ol)::after,
 .text:withSafariListsFix > ul::after,
 .text:withSafariListsFix > ol::after {
  content: "\A";
  white-space: pre-wrap;
}

.text:withSafariListsFix > ul,
.text:withSafariListsFix > ol {
  list-style-position: inside;
}

.text:wrappingStyle(multi-line) > *:has(br)::after {
  content: none;
}

.text:wrappingStyle(single-line) {
  white-space: nowrap;
}

.text:wrappingStyle(single-line):collapse {
  text-overflow: ellipsis;
}

.text:collapse {
  overflow: hidden;
}

.expand-control {
  -archetype: text;
  margin-top: getVar('--expand-control-spacing');
  cursor: pointer;
  display: inline;
  font-size: 16px;
  letter-spacing: 0em;
  align-self: getVar('--expand-control-align');
}

