@namespace 'StylableButton';

:import {
  -st-from: '../../../stylable/corvid.js';
  -st-named:
    corvidBackgroundColor,
    corvidHoverBackgroundColor,
    corvidDisabledBackgroundColor,
    corvidBorderColor,
    corvidHoverBorderColor,
    corvidDisabledBorderColor,
    corvidTextColor,
    corvidHoverTextColor,
    corvidDisabledTextColor,
    corvidIconColor,
    corvidHoverIconColor,
    corvidDisabledIconColor,
    corvidBorderRadius,
    corvidBorderWidth;
}

:import {
  -st-from: './formatter.js';
  -st-named: LayoutFlexChildSpacing;
}

.root {
  -archetype: box;
  /* -st-states: error, disabled;  - StylableButton states are currently commented out in Bolt also */
  -st-states:
    hasBackgroundColor,
    hasBorderColor,
    hasBorderRadius,
    hasBorderWidth,
    hasIconColor,
    hasColor,

    hasHoverBackgroundColor,
    hasHoverBorderColor,
    hasHoverIconColor,
    hasHoverColor,

    hasDisabledBackgroundColor,
    hasDisabledBorderColor,
    hasDisabledIconColor,
    hasDisabledColor,

    isMaxContent,
    isWrapText;

  cursor: pointer;
  border: 0;
  display: block;
  min-width: 10px;
  min-height: 10px;
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  padding: 0px;
  touch-action: manipulation;
}

.root[disabled] {
  pointer-events: none;
}

.root:not(:hover):not([disabled]):hasBackgroundColor {
  background-color: corvidBackgroundColor() !important;
}
.root:hover:not([disabled]):hasHoverBackgroundColor {
  background-color: corvidHoverBackgroundColor() !important;
}
.root:not(:hover)[disabled]:hasDisabledBackgroundColor {
  background-color: corvidDisabledBackgroundColor() !important;
}

.root:not(:hover):not([disabled]):hasBorderColor {
  border-color: corvidBorderColor() !important;
}
.root:hover:not([disabled]):hasHoverBorderColor {
  border-color: corvidHoverBorderColor() !important;
}
.root:not(:hover)[disabled]:hasDisabledBorderColor {
  border-color: corvidDisabledBorderColor() !important;
}

.root:hasBorderRadius {
  border-radius: corvidBorderRadius() !important;
}

.root:hasBorderWidth {
  border-width: corvidBorderWidth() !important;
}

.root:not(:hover):not([disabled]):hasColor,
.root:not(:hover):not([disabled]):hasColor .label {
  color: corvidTextColor() !important;
}
.root:hover:not([disabled]):hasHoverColor,
.root:hover:not([disabled]):hasHoverColor .label {
  color: corvidHoverTextColor() !important;
}
.root:not(:hover)[disabled]:hasDisabledColor,
.root:not(:hover)[disabled]:hasDisabledColor .label {
  color: corvidDisabledTextColor() !important;
}

.link {
  -archetype: box;
  text-decoration: none;
  box-sizing: border-box;
  color: black;
}

.container {
  display: flex;
  flex-basis: auto;
  justify-content: center;
  flex-direction: row;
  flex-grow: 1;
  align-items: center;
  overflow: hidden;
  height: 100%;
  width: 100%;
  transition: all 0.2s ease, visibility 0s;
}

.label {
  -archetype: text;
  -controller-part-type: LayoutChildDisplayDropdown,
    LayoutFlexChildSpacing(first);
  overflow: hidden;
  text-overflow: ellipsis;
  text-align: center;
  white-space: nowrap;
  min-width: 1.8em;
  max-width: 100%;
  transition: inherit;
}

.root:isMaxContent .label {
   text-overflow: unset;
}

.root:isWrapText .label{
  overflow-wrap: break-word;
  white-space: break-spaces;
  word-break: break-word;
  min-width: 10px;
}

.icon {
  -archetype: icon;
  -controller-part-type: LayoutChildDisplayDropdown,
    LayoutFlexChildSpacing(last);
  -st-states: override;
  min-width: 1px;
  height: 50px;
  transition: inherit;
  flex-shrink: 0;
}

.icon:override {
  display: block !important;
}

.icon > span,
.icon svg {
  display: flex;
  width: inherit;
  height: inherit;
}

.root:not(:hover):not([disalbed]):hasIconColor .icon svg {
  fill: corvidIconColor() !important;
  stroke: corvidIconColor() !important;
}
.root:hover:not([disabled]):hasHoverIconColor .icon svg {
  fill: corvidHoverIconColor() !important;
  stroke: corvidHoverIconColor() !important;
}
.root:not(:hover)[disabled]:hasDisabledIconColor .icon svg {
  fill: corvidDisabledIconColor() !important;
  stroke: corvidDisabledIconColor() !important;
}

