@namespace 'HamburgerOverlay';

@property st-global(--above-all-z-index);
@property st-global(--wix-ads-height);

.root {
  -archetype: paintBox;
  -st-states: isMenuOpen, showBackgroundOverlay, shouldScroll;
  visibility: hidden;
  box-sizing: border-box;
  /* !important is required because we need to override size and position set on the root element by the Viewer. */
  height: calc(100vh - var(--wix-ads-height)) !important;
  width: 100vw !important;
  position: fixed !important;
  top: var(--wix-ads-height) !important;
  left: 0;
  /* make sure overlay covers elements with pinned to page */
  z-index: var(--above-all-z-index);
}

.overlay {
  box-sizing: border-box;
  height: 100%;
  width: 100%;
  position: absolute;
  top: 0;
  left: 0;
}

.root:isMenuOpen {
  visibility: visible;
}

.root:not(:showBackgroundOverlay) {
  background-color: transparent;
}

.root:shouldScroll {
  overflow-x: hidden;
  overflow-y: scroll;
}

.scrollContent{
  position: relative;
}

