  width: calc(value(--variant-count) * 0.1px);
  visibility: hidden;
  position: absolute;
  top: 0;
  left: 0;
  pointer-events: none;
}
:root {
  --overFreemiumBanner: 1000000;
  --overFullscreen: 1000001;
}

.container {
  overflow: auto;
  overflow-x: hidden;
}

.container-prerender {
  min-height: max-content;
  height: 100%;
}

.root {
  -archetype: paintBox;
  height: 100%;
  width: 100%;
  max-height: 100%;
  box-sizing: border-box;
}
.pro-gallery-container {
  -archetype: paintBox;
  -st-global: '.pro-gallery-parent-container'
}
.item {
  -st-global: ".gallery-item-container";
  -st-extends: Item;
  transition: all .3s, width 0s, height 0s;
}
.item::content {
  transition: all .3s, width 0s, height 0s;
}
