@property st-global(--MinThumbPos);
@property st-global(--MaxThumbPos);
@property st-global(--defaultThumbHeight);
@property st-global(--root-direction);
@property st-global(--label-direction);
@property st-global(--slider-direction);
@property st-global(--align);

@namespace 'RangeSlider';

:import {
  -st-from: "/a43e067f242fede1756fdeba51ed3071c957a6c1.st.css";
  -st-default: Slider;
  -st-named: markLabel, sliderRailHeight, sliderHandleTooltip, sliderThumbSize, sliderPadding, sliderHandle, markLine, sliderThumb;
}

:import {
  -st-from: "/58a152f7119bb0fa4ce02f3676375d53c1294a0e.st.css";
  -st-default: Tooltip;
}

:vars {
  sliderMarkDotSize: 3px;
  sliderMarkLineHeight: 10px;
  sliderMarkMarginSpace: 7px;
}

.container {
  height: auto !important;
}

.root {
  -archetype: box;
  -st-states: sliderType(enum(Stepped, Continuous)),thumbShape(enum(Circle, Square, Rectangle, Bar)),
   marksTickShape(enum(Lines, Dots)), direction(enum(rtl, ltr)), singleHandle;
   --label-left-padding: 0;
   --label-right-padding: 0;
   --label-bottom-padding: 0;
   --rail-percentage: 50;
   --thumbHeight: 24px;
   --thumbWidth: var(--thumbHeight);
   --halfThumbWidth:  calc(0.5 * var(--thumbWidth));
   --minThumbDeviation: calc(var(--thumbWidth) * var(--MinThumbPos));
   --maxThumbDeviation:  calc(var(--thumbWidth) * var(--MaxThumbPos));
   --maxThumbOppositeDeviation: calc((1 - var(--MaxThumbPos)) * var(--thumbWidth));

   direction: var(--root-direction);
}

.root:sliderType(Stepped):marksTickShape(Lines){
  padding-bottom: calc(value(sliderMarkLineHeight) + value(sliderMarkMarginSpace));
}

.root:sliderType(Stepped):marksTickShape(Dots){
  padding-bottom: calc(value(sliderMarkDotSize) + value(sliderMarkMarginSpace));
}

/** Implemented the space between slider and label with padding (and not margin) because of the bounding box and slider heigh structure. */
.label {
  -archetype: text;
  direction: var(--label-direction);
  display: block;
  text-align: var(--align);
  font-family: Helvetica;
  font-size: 18px;
  padding-left: var(--label-left-padding);
  padding-right: var(--label-right-padding);
  padding-bottom: var(--label-bottom-padding);
}

.baseSlider {
  -st-extends: Slider;
  -st-mixin: Slider(sliderRailHeight calc(var(--thumbHeight)*(var(--rail-percentage)/ 100)), sliderThumbSize var(--thumbHeight));
}

.baseSlider::sliderHandleWrapper {
  margin-top: calc(var(--thumbHeight)*-1);
}

.baseSlider::slider::slider-mark {
  margin-top: calc((var(--thumbHeight)) * (1 - var(--rail-percentage)/ 100));
  width: calc(100% - var(--thumbWidth));
  margin-left: calc(var(--thumbWidth)/2);
}

.baseSlider .markLine{
  -st-global: '.wsr-slider-step';
  -archetype: noPaddingBox;
}

.root .markLabel {
  display: none;
  -archetype: text;
}

.slider-rail {
  -st-global: '.wsr-slider-rail';
  -archetype: paintBox;
  box-sizing: border-box;
}

.baseSlider {
  direction: var(--slider-direction);
}

.baseSlider::slider {
  display: flex;
  align-items: center;
  height: calc(var(--thumbHeight) + 2 * value(sliderPadding));
}

.baseSlider .sliderThumb{
  box-sizing: border-box;
  -archetype: paintBox;
  border-top-left-radius: 50%;
  border-top-right-radius: 50%;
  border-bottom-left-radius: 50%;
  border-bottom-right-radius: 50%;
}

.root::baseSlider::sliderThumb {
  width: var(--thumbWidth);
  top: 0;
  bottom: 0;
}

.slider-track {
  -st-global: '.wsr-slider-track';
  -archetype: onlyPaintBox;
}

.baseSlider::slider-track {
  width: auto !important;
}

.root .baseSlider::slider-track {
  inset-inline-start: calc(100% * var(--MinThumbPos) - var(--minThumbDeviation) + var(--halfThumbWidth)) !important;
  inset-inline-end: calc(100% * (1 - var(--MaxThumbPos)) -  var(--maxThumbOppositeDeviation) + var(--halfThumbWidth)) !important;
}

.root:singleHandle .baseSlider::slider-track {
  inset-inline-start: 0% !important;
  inset-inline-end: calc(100% * (1 - var(--MaxThumbPos)) -  var(--maxThumbOppositeDeviation) + var(--halfThumbWidth)) !important;
}

.root:marksTickShape(Lines)::baseSlider::markLine {
  width: 1px;
  height: value(sliderMarkLineHeight);
}

.root:marksTickShape(Dots)::baseSlider::markLine {
  width: value(sliderMarkDotSize);
  height: value(sliderMarkDotSize);
  border-radius: 50%;
}

.baseSlider::sliderHandleWrapper .sliderHandle{
  transform: translateX(0%) !important;
}

.root .baseSlider::sliderHandleWrapper:nth-child(4) .sliderHandle {
  inset-inline-start: calc(100% * var(--MinThumbPos) - var(--minThumbDeviation)) !important;
}
.root .baseSlider::sliderHandleWrapper:nth-child(5) .sliderHandle {
  inset-inline-start: calc(100% * var(--MaxThumbPos) - var(--maxThumbDeviation)) !important;
}

.baseSlider::sliderThumb:hovered {
  transform: scale(1) !important;
}

