@namespace 'RichContentViewer';

@property st-global(--display);

:import {
  -st-from: '../../../../stylable/params.js';
  -st-named: getVar, color;
}

.root {
  -st-states: isCollapsed;
  width: 100%;
  display: block;
  direction: getVar(--direction, ltr);
  box-sizing: border-box;
}

.root:isCollapsed {
  height: calc(1px * getVar(--collapseHeight, 200));
  overflow: hidden;
}
.root:isCollapsed::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
