:import {
  -st-from: '../../../../../../stylable/params.js';
  -st-named: getVar;
}

:vars {
  columns-count: getVar(--columnsAmount);
  horizontal-spacing: getVar(--horizontalSpacing);
  white-space: getVar(--white-space);
  is-animated: getVar(--is-animated);
  /* set from positionUpdaters.js */
  animation-box-max-height: getVar(--max-height, 'none');
  animation-box-overflow-y: getVar(--overflow-y, 'visible');
  position-box-z-index: getVar(--position-box-z-index, 47);
}

.root {
  -archetype: paintBox;
  -st-states: isHovered, isCurrentPage;

  display: block;
  cursor: pointer;
  text-decoration: none;
  flex: 1;
}

.root:isHovered,
.root:isCurrentPage,
.root:isHovered::label,
.root:isCurrentPage::label {
  transition: all 0.08s cubic-bezier(0, 0, 1, 1);
}

.container {
  -archetype: box;
  display: flex;
  height: 100%;
  align-items: center;
}

.label {
  -archetype: text;
  -controller-part-type: LayoutChildDisplayDropdown;
  white-space: nowrap;
  transition: inherit;
}

.itemWrapper {
  flex-grow: inherit;
}

.positionBox {
  -st-states: isStretched, isColumn;
  display: none;
  position: fixed;
  margin: auto;
  z-index: value(position-box-z-index);
}

.positionBox:isColumn {
  position: absolute;
  left: 0;
  right: 0;
}

.positionBox:isStretched {
  max-width: unset;
}

@keyframes fadeIn {
  from { opacity: 0 }
  to { opacity: 1 }
}

.animationBox {
  transition: border-color 0.08s cubic-bezier(0.25, 1, 0.5, 1),
  box-shadow 0.08s cubic-bezier(0.25, 1, 0.5, 1);
  opacity: 0;
  animation-duration: calc(value(is-animated) * 0.1s);
  animation-delay: calc(value(is-animated) * 0.05s);
  animation-fill-mode: forwards;
  max-height: value(animation-box-max-height);
  overflow-y: value(animation-box-overflow-y);
}

.positionBox:isStretched>.animationBox {
  width: 100%;
}
.positionBox:isStretched .megaMenuComp {
  width: 100% !important;
}

.alignBox {
  display: flex;
}

.list {
  column-gap: calc(1px * value(horizontal-spacing));
}

.itemWrapper[data-hovered]>.positionBox {
  display: block;
  visibility: hidden;
}

.itemWrapper[data-shown]>.positionBox {
  display: block;
  visibility: visible;
}


.itemWrapper[data-hovered]>.positionBox>.animationBox {
  animation-name: fadeIn;
}

.megaMenuComp {
  margin-top: getVar(containerMarginTop) !important;
  padding: 0 !important;
  flex-shrink: 0;
  direction: ltr;
}

/* for proper display in the editor */
.itemWrapper:not([data-hovered]) .megaMenuComp {
  display: none;
}

/* CSS pre-hydration: show stretched mega menu on hover before React hydrates.
   position:fixed bypasses the containing block so the dropdown spans the
   viewport, matching the JS positionUpdater behaviour for stretched menus.
   JS corrects to exact position after hydration. */

:global([data-prehydration]) .itemWrapper:hover>.positionBox:isColumn:isStretched {
  display: block;
  position: fixed !important;
}

:global([data-prehydration]) .itemWrapper:hover>.positionBox:isColumn>.animationBox {
  opacity: 1;
}

:global([data-prehydration]) .itemWrapper:hover>.positionBox:isColumn .megaMenuComp {
  display: block;
}

