:import {
  -st-from: '../../../../core/stylable/params.js';
  -st-named: getVar, color;
}

@property st-global(--force-state-metadata);

:import {
  -st-from: "/b28aa2f8585ce80edd5834e7797cf0f287137717.st.css";
  -st-named: focus-ring-active as focus-ring;
}

:vars {
  filledShapeColor: color(--filledShapeColor, color_5);
  emptyShapeColor: color(--emptyShapeColor, color_15);

  shapeBorderColor: color(--shapeBorderColor, color_32);
  shapeBorderWidth: getVar(--shapeBorderWidth, 3);

  labelFont: getVar(--labelFont, --font_8);
  labelFontColor: color(--labelFontColor, color_15);

  errorFilledShapeColor: color(--errorFilledShapeColor, color_7);
  errorShapeBorderColor: color(--errorShapeBorderColor, color_37);
  errorShapeBorderWidth: getVar(--errorShapeBorderWidth, 7);

  focusEmptyShapeColor: color(--focusEmptyShapeColor, '176, 171, 186');
  focusShapeBorderColor: color(--focusShapeBorderColor, '176, 171, 186');
  focusShapeBorderWidth: getVar(--focusShapeBorderWidth, 1);

  iconSize: getVar(--iconSize, auto);
}

.root {
  display: inline-block;
  -st-states: disabled, checked, focused, focus-ring-visible, error;
}

.root:disabled {
  filter: grayscale(75%);
  opacity: 0.7;
}

.hiddenInput {
  position: absolute;
  overflow: hidden;
  height: 1px;
  width: 1px;
  margin: -1px;
  padding: 0;
  border: 0;
  opacity: 0;
}

.icon {
  -st-states: checked;

  cursor: pointer;
  width: value(iconSize);
  height: value(iconSize);
  display: block;
  position: relative;
  stroke: value(shapeBorderColor);
  stroke-width: value(shapeBorderWidth);
  fill: value(emptyShapeColor);
}

.icon path {
  fill: value(emptyShapeColor);
}

.icon:checked path {
  fill: value(filledShapeColor);
}

.icon svg {
  display: block;
  height: 100%;
  width: 100%;
  transform: translateZ(0);
}

.root:focused .icon:not(:checked) path {
  fill: value(focusEmptyShapeColor);
}

.root:focused .icon {
  stroke: value(focusShapeBorderColor);
  stroke-width: value(focusShapeBorderWidth);
}

.root:focus-ring-visible .icon {
  -st-mixin: focus-ring;
}

.icon:not(:checked) {
  --force-state-metadata: false;
}

.root:error::icon:not(:checked){
  stroke: value(errorShapeBorderColor);
  stroke-width: value(errorShapeBorderWidth);
}

.root:error::icon:not(:checked) path{
  fill: value(errorFilledShapeColor);
}
